using System;
using System.Collections.Generic;
using System.ServiceModel;
using HealthCareService.Contracts;

namespace HealthCareService
{
    [ServiceBehavior(InstanceContextMode = InstanceContextMode.Single)]
    public class PatientService : IPatientService
    {
        private readonly Dictionary<string, PatientRecord> _patientRecords = new Dictionary<string, PatientRecord>();

        public PatientService()
        {
            // Seed with some dummy data
            _patientRecords.Add("P001", new PatientRecord
            {
                PatientId = "P001",
                FirstName = "Alice",
                LastName = "Smith",
                DateOfBirth = new DateTime(1980, 5, 15),
                SocialSecurityNumber = "111-22-3333",
                Address = "123 Main St, Anytown, USA",
                Diagnosis = "Hypertension",
                Medication = "Lisinopril",
                LastUpdated = DateTime.UtcNow
            });
            _patientRecords.Add("P002", new PatientRecord
            {
                PatientId = "P002",
                FirstName = "Bob",
                LastName = "Johnson",
                DateOfBirth = new DateTime(1975, 11, 22),
                SocialSecurityNumber = "444-55-6666",
                Address = "456 Oak Ave, Otherville, USA",
                Diagnosis = "Type 2 Diabetes",
                Medication = "Metformin",
                LastUpdated = DateTime.UtcNow
            });
        }

        public PatientRecord GetPatientRecord(string patientId)
        {
            Console.WriteLine($"Received GetPatientRecord request for ID: {patientId} at {DateTime.Now}");
            if (_patientRecords.TryGetValue(patientId, out PatientRecord record))
            {
                return record;
            }
            throw new FaultException($"Patient with ID {patientId} not found.");
        }

        public void AddPatientRecord(PatientRecord record)
        {
            Console.WriteLine($"Received AddPatientRecord request for ID: {record.PatientId} at {DateTime.Now}");
            if (_patientRecords.ContainsKey(record.PatientId))
            {
                throw new FaultException($"Patient with ID {record.PatientId} already exists.");
            }
            record.LastUpdated = DateTime.UtcNow;
            _patientRecords.Add(record.PatientId, record);
            Console.WriteLine($"Added patient: {record.FirstName} {record.LastName}");
        }

        public void UpdatePatientRecord(PatientRecord record)
        {
            Console.WriteLine($"Received UpdatePatientRecord request for ID: {record.PatientId} at {DateTime.Now}");
            if (!_patientRecords.ContainsKey(record.PatientId))
            {
                throw new FaultException($"Patient with ID {record.PatientId} not found for update.");
            }
            record.LastUpdated = DateTime.UtcNow;
            _patientRecords[record.PatientId] = record;
            Console.WriteLine($"Updated patient: {record.FirstName} {record.LastName}");
        }

        public List<PatientRecord> GetAllPatientRecords()
        {
            Console.WriteLine($"Received GetAllPatientRecords request at {DateTime.Now}");
            return new List<PatientRecord>(_patientRecords.Values);
        }
    }
}

