using System;
using System.Collections.Generic;
using System.ServiceModel;
using HealthCareService.Contracts;

namespace HealthCareService.Client
{
    class Program
    {
        static void Main(string[] args)
        {
            // Use a ChannelFactory to create the proxy programmatically
            // Configuration in App.config for client is also necessary
            ChannelFactory<IPatientService> factory = new ChannelFactory<IPatientService>("PatientServiceEndpoint");
            IPatientService proxy = factory.CreateChannel();

            try
            {
                Console.WriteLine("--- Testing Service Operations ---");

                // Get a patient record (encrypted data in response)
                Console.WriteLine("\nGetting Patient P001:");
                PatientRecord patient1 = proxy.GetPatientRecord("P001");
                Console.WriteLine($"Retrieved: {patient1}");

                // Add a new patient record (encrypted data in request)
                Console.WriteLine("\nAdding New Patient P003:");
                PatientRecord newPatient = new PatientRecord
                {
                    PatientId = "P003",
                    FirstName = "Charlie",
                    LastName = "Brown",
                    DateOfBirth = new DateTime(1995, 8, 10),
                    SocialSecurityNumber = "777-88-9999",
                    Address = "789 Pine Ln, Somewhere, USA",
                    Diagnosis = "Common Cold",
                    Medication = "None",
                    LastUpdated = DateTime.UtcNow
                };
                proxy.AddPatientRecord(newPatient);
                Console.WriteLine($"Added patient P003.");

                // Verify the new patient
                Console.WriteLine("\nGetting New Patient P003 to verify:");
                PatientRecord retrievedNewPatient = proxy.GetPatientRecord("P003");
                Console.WriteLine($"Verified: {retrievedNewPatient}");

                // Update a patient record (encrypted data in request)
                Console.WriteLine("\nUpdating Patient P002 Medication:");
                PatientRecord patient2 = proxy.GetPatientRecord("P002");
                patient2.Medication = "Metformin + Insulin";
                proxy.UpdatePatientRecord(patient2);
                Console.WriteLine($"Updated patient P002.");

                // Verify the update
                Console.WriteLine("\nGetting Patient P002 to verify update:");
                PatientRecord updatedPatient2 = proxy.GetPatientRecord("P002");
                Console.WriteLine($"Verified: {updatedPatient2}");

                // Get all patient records
                Console.WriteLine("\nGetting All Patient Records:");
                List<PatientRecord> allRecords = proxy.GetAllPatientRecords();
                foreach (var record in allRecords)
                {
                    Console.WriteLine($"- {record}");
                }

                Console.WriteLine("\nOperations completed successfully. All sensitive data was encrypted.");
            }
            catch (FaultException ex)
            {
                Console.WriteLine($"Service Fault: {ex.Message}");
            }
            catch (CommunicationException ex)
            {
                Console.WriteLine($"Communication Error: {ex.Message}");
                if (ex.InnerException != null)
                {
                    Console.WriteLine($"Inner Exception: {ex.InnerException.Message}");
                }
            }
            catch (TimeoutException ex)
            {
                Console.WriteLine($"Operation timed out: {ex.Message}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"An unexpected error occurred: {ex.Message}");
            }
            finally
            {
                // Ensure the channel is closed gracefully
                ICommunicationObject commObject = proxy as ICommunicationObject;
                if (commObject != null)
                {
                    if (commObject.State == CommunicationState.Opened)
                        commObject.Close();
                    else if (commObject.State == CommunicationState.Faulted)
                        commObject.Abort();
                }
                factory.Close();
            }

            Console.WriteLine("\nPress <Enter> to exit.");
            Console.ReadLine();
        }
    }
}

